CREATE POLICY "Admins manage prod_order_headers_current"
ON public.prod_order_headers_current
FOR ALL
USING (has_role(auth.uid(), 'admin'::app_role))
WITH CHECK (has_role(auth.uid(), 'admin'::app_role));

